from django.contrib.auth import authenticate, login
from django.shortcuts import render
from django.views.decorators.csrf import csrf_exempt
from saml2.metadata import parse_saml_metadata
from saml2.response import SamlResponse
from saml2.xmlparser import BeautifulSoup
from django.contrib.sessions.models import Session

@csrf_exempt
def saml_response(request):
    response = SamlResponse(request.body.decode('utf-8'))
    response.validate()
    xml = BeautifulSoup(response.xml, 'xml')

    # Extract user information from assertion attributes
    name_id = xml.find('saml:NameID').text
    attributes = {}
    for attr in xml.find_all('saml:Attribute'):
        attributes[attr['Name']] = attr.find('saml:AttributeValue').text

    # Create Django user session
    user = authenticate(username=name_id, attributes=attributes)
    if user is not None:
        login(request, user)
        session = Session.objects.create(user=user)
        session.save()

    return render(request, 'saml_response.html')